def kmeans_fit(data):
    x = data[1:, :] / data[:-1, :] - 1
    flag = np.all(~(np.isnan(x) | np.isinf(x)), axis=1)
    x = x[flag]
    if len(x) <= 60:
        return np.nan
    model = KMeans(n_clusters=2)
    model.fit(x)
    labels = model.labels_
    if np.mean(labels) > 0.5:
        labels = 1 - labels
    jump_labels = np.where(labels, 1, np.nan)
    return np.nanstd(x[0, :] * jump_labels)

def cal_factors(data, turnover):
    q = data.nlargest(10)
    q.sort_index(inplace=True)
    top_idx = np.array(q.index.tolist())
    while True:
        diff = np.insert(np.diff(top_idx, 1) > 6, 0, True)
        if np.all(diff):
            break
        top_idx = top_idx[diff]
    top_vol, follow_vol, top_money, follow_money = 0, 0, 0, 0

    for i in top_idx:
        top_vol += q.loc[i]
        top_money += turnover.iloc[i]
        for j in range(1, 6):
            if i + j < 225:
                follow_vol += data.iloc[i + j]
                follow_money += turnover.iloc[i + j]
    return [follow_money / follow_vol, top_money / top_vol, turnover.sum() / data.sum()]

def cal_factors(data):
    res = []
    for i in range(5, len(data)):
        all_price = data[i-5:i, :]
        sigma = np.nanstd(all_price)
        mu = np.nanmean(all_price)
        if data[i-1, 2] > sigma + mu:
            res.append('u')
        elif data[i-1, 2] < mu - sigma:
            res.append('l')
        else:
            res.append('b')
    return res

def cal_factors(data):
    close, time_list = [], [0]
    thd = round(np.nansum(data[:, 0]) / 50, 2)
    if thd == 0:
        return [np.nan] * 6
    cur_vol, cur_close = 0, 0

    for i in range(len(data)):
        diff = round(thd - cur_vol, 2)
        if data[i, 0] is None:
            continue
        if diff - data[i, 0] <= 0.01:
            cur_close += data[i, 1] * diff / thd
            close.append(cur_close)
            cur_vol = (data[i, 0] - diff)
            time_list.append(i + 1)
            while thd - cur_vol <= 0.01:
                time_list.append(i+1)
                close.append(data[i, 1])
                cur_vol -= thd
            else:
                cur_close = cur_vol * data[i, 1] / thd
        else:
            cur_close += data[i, 0] * data[i, 1] / thd
            cur_vol += data[i, 0]
    time_list = np.diff(time_list)
    time_list_2 = np.diff(time_list)
    ret = np.diff(close) / np.array(close)[:-1]
    return [np.mean(time_list), np.var(time_list), np.mean(ret), np.var(ret),
            np.mean(time_list_2), np.var(time_list_2)]

def cal_factors(data):
    rv_cum = []
    time_cum = []
    tmp_cum = data.iloc[0]
    for i in range(1, len(data)):
        tmp_rv = data.iloc[i]
        if tmp_cum > 0 and tmp_rv > 0:
            tmp_cum += tmp_rv
        elif tmp_cum < 0 and tmp_rv < 0:
            tmp_cum += tmp_rv
        else:
            rv_cum.append(tmp_cum)
            if not time_cum:
                time_cum.append(i)
            else:
                time_cum.append(i - time_cum[-1])
            tmp_cum = tmp_rv

    rv_v = []
    rv_weight_v = []
    for i in range(1, len(rv_cum)):
        condition = rv_cum[i-1] + rv_cum[i]
        if rv_cum[i-1] < 0  and condition < 0:
            rv_v.append(np.abs(condition))
            rv_weight_v.append(rv_v[-1] / (time_cum[i-1] + time_cum[i]))
    if not rv_v:
        return [np.nan] * 4
    return [np.mean(rv_v), np.max(rv_v), np.mean(rv_weight_v), np.max(rv_weight_v)]

def cal_factors(self, close, flag):
    idx = []
    for i in range(len(flag)):
        if flag.iloc[i]:
            idx.append(i)
        if len(idx) == 2:
            break
    if len(idx) < 2:
        return np.nan
    intraday_mom = close.iloc[idx[-1]] / close.iloc[idx[0]] - 1
    return intraday_mom

def __cal_beta__(data):
    y = np.abs(data.iloc[:, 0].values)
    if len(y) < 5:
        return [np.nan] * 3
    beta = []
    for i in range(1, 4):
        x = np.c_[np.ones((len(data), 1)), data.iloc[:, i].values]
        beta_full = np.linalg.pinv(x.T @ x) @ x.T @ y
        beta.append(beta_full[-1])
    return beta

def __cal_factors__(self, group):
    group.sort_values(by='cap', inplace=True)
    start = 0
    for q in [0.3, 0.7, 1]:
        end = int(len(group) * q)
        tmp_group = group.iloc[start:end]
        codes = tmp_group.index.tolist()
        tmp_data = self.rtn_1[codes]
        tmp_data[:] = tmp_data.mean(axis=1).values[:, np.newaxis]
        if self.res is None:
            self.res = tmp_data.quantile([0.05, 0.95])
        else:
            self.res = self.res.join(tmp_data.quantile([0.05, 0.95]))
        start = end

def cal_resi(data):
    if data.iloc[:, 0].sum() == 0:
        return None
    lr = LinearRegression()
    lr.fit(data.iloc[:, 1:], data.iloc[:, 0:1])
    resi = data.iloc[:, 0:1] - lr.predict(data.iloc[:, 1:])
    return resi / resi.std()

def cal_resi(y, x):
        data = pd.concat([y, x], axis=1).dropna()
        if len(data) < 60 or data.iloc[:, 0].sum() == 0:
            return pd.Series(index=y.index, name=y.name)
        lr = LinearRegression()
        lr.fit(data.iloc[:, 1:], data.iloc[:, 0:1])
        resi = data.iloc[:, 0:1] - lr.predict(data.iloc[:, 1:])
        return resi

def __cal_factors__(self, data):
    mu = data.mean()
    data = data.dropna()
    if len(data) < 60:
        return np.nan
    new_data = -data + 2 * mu
    asym = self.compute_mmd(data.values, new_data.values)
    return asym
@staticmethod

def __cal_factors__(self, data):
    data = data.dropna()
    if len(data) < 200:
        return np.nan
    x = data.iloc[:, :-1].values
    y = data.iloc[:, -1:].values
    lr = LinearRegression()
    lr.fit(x, y)
    return np.mean(lr.coef_)

def cal_factor(data):
    close_idx = None
    close = data.iloc[-1, 0]
    rtn = data.iloc[-1, 0] / data.iloc[0, -1] - 1
    q = data['close'].quantile([i / 10 for i in range(11)])
    data.sort_values(by='close', inplace=True)
    vol_group = []
    end = 1
    tmp_vol = 0
    for i in range(len(data)):
        if data.iloc[i, 0] <= q.iloc[end]:
            tmp_vol += data.iloc[i, 1]
        else:
            vol_group.append(tmp_vol)
            tmp_vol = data.iloc[i, 1]
            end += 1
        if data.iloc[i, 0] == close and close_idx is None:
            close_idx = end
    vol_group.append(tmp_vol)
    if len(vol_group) < 10:
        vol_group += [0] * (10 - len(vol_group))
    vol_group = np.array(vol_group) / np.sum(vol_group)
    v_p_skewness = 3 * (np.mean(vol_group) - np.median(vol_group)) / np.std(vol_group)
    poc_list = []
    for i in range(len(vol_group)):
        if i == 0:
            poc_list.append(2 * vol_group[i] + vol_group[i + 1])
        elif i == len(vol_group) - 1:
            poc_list.append(2 * vol_group[i] + vol_group[i - 1])
        else:
            poc_list.append(vol_group[i - 1] + vol_group[i] + vol_group[i + 1])
    poc_idx = np.argmax(poc_list)
    if rtn < 0:
        v_p_reversal = (poc_idx - close_idx + 1) * rtn
    else:
        v_p_reversal = (close_idx - poc_idx + 1) * rtn
    return [v_p_skewness, v_p_reversal]

def cal_factors(self, data):
    absolute_deviation = np.abs(data - data.median())
    mad = np.nanmedian(absolute_deviation)
    thd = 5 * mad
    # thd = 3 * data.std()
    res = [0, 1]
    for i in range(2, len(data)):
        for j in range(i-1, -1, -1):
            if abs(data.iloc[i] - data.iloc[j]) > thd:
                res.append(i - j)
                break
        if len(res) != i + 1:
            res.append(i)
    res = np.array(res)
    mu, sigma, max_val = np.mean(res), np.std(res), np.max(res)
    extreme = np.mean(res > mu + 2 * sigma)
    return np.mean(res), np.std(res), max_val, max_val - np.min(res), extreme, np.mean(res[:120]) / np.mean(res[120:])
